(function registerMobileTabletV2(global) {
  const { useCallback, useEffect, useMemo, useRef, useState } = React;
  const {
    Activity, AlarmClock, ArrowDown, ArrowLeft, ArrowRightLeft, ArrowUp, Award,
    BarChart3, Bell, BookOpen, CalendarDays, Check, CheckCircle2, ChevronDown,
    ChevronLeft, ChevronRight, Circle, Clock3, CreditCard, Download, Droplet,
    Dumbbell, FileSpreadsheet, FileText, Flame, HeartPulse, Home, ListFilter,
    Medal, Menu, Mic, Moon, MoreHorizontal, Pause, Pill, Play, Plus, RefreshCcw,
    Search, Settings, Sparkles, Target, Timer, Tooth: ToothIcon, TrendingUp, Trophy, WalletCards,
    X
  } = global.lucideReact;
  const Tooth = ToothIcon || Sparkles;

  const isoDate = (date = new Date()) => {
    const local = new Date(date.getTime() - date.getTimezoneOffset() * 60000);
    return local.toISOString().slice(0, 10);
  };
  const uid = (prefix) => `${prefix}_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
  const money = (value, currency = 'COP') => new Intl.NumberFormat('es-CO', {
    style: 'currency', currency, maximumFractionDigits: currency === 'COP' ? 0 : 2
  }).format(Number(value || 0));
  const shortDate = (value) => {
    const date = new Date(`${value || isoDate()}T12:00:00`);
    return date.toLocaleDateString('es-CO', { day: 'numeric', month: 'short' });
  };
  const minutes = (value) => `${String(Math.floor(value / 60)).padStart(2, '0')}:${String(value % 60).padStart(2, '0')}`;
  const initials = (name) => String(name || 'U').trim().slice(0, 1).toUpperCase();
  const allAgendaItems = (agenda) => Object.entries(agenda || {}).flatMap(([date, rows]) => (rows || []).map(row => ({ ...row, date: row.dueDate || date })));
  const activeHabits = (data) => (data.habits || []).filter(item => item.active !== false);
  const recordsFor = (data, habitId, date = isoDate()) => (data.records || []).some(record => record.habitId === habitId && record.date === date && record.completed);
  const routeParam = (name, fallback) => new URLSearchParams(location.search).get(name) || fallback;
  const useMobileV2Viewport = () => {
    const read = () => global.matchMedia('(max-width: 1180px)').matches;
    const [isMobileTablet, setMobileTablet] = useState(read);
    useEffect(() => {
      const media = global.matchMedia('(max-width: 1180px)');
      const update = () => setMobileTablet(media.matches);
      media.addEventListener?.('change', update);
      return () => media.removeEventListener?.('change', update);
    }, []);
    return { isMobileTablet, isPhone: global.matchMedia('(max-width: 767px)').matches };
  };

  const IconCircle = ({ children, tone = 'red', className = '' }) => <span className={`m2-icon m2-icon-${tone} ${className}`}>{children}</span>;
  const Card = ({ children, className = '', as: Tag = 'section', ...props }) => <Tag className={`m2-card ${className}`.trim()} {...props}>{children}</Tag>;
  const PageTitle = ({ title, subtitle, action }) => <div className="m2-title-row"><div><h1>{title}</h1><p>{subtitle}</p></div>{action}</div>;
  const Tabs = ({ items, value, onChange, label }) => <div className="m2-tabs" role="tablist" aria-label={label}>{items.map(item => <button type="button" role="tab" aria-selected={value === item.id} className={value === item.id ? 'is-active' : ''} key={item.id} onClick={() => onChange(item.id)}>{item.icon && <item.icon size={19} />}{item.label}</button>)}</div>;
  const Button = ({ children, secondary = false, className = '', ...props }) => <button type="button" className={`m2-button ${secondary ? 'is-secondary' : ''} ${className}`.trim()} {...props}>{children}</button>;
  const Empty = ({ icon: Icon = Sparkles, title, text, action, actionLabel }) => <Card className="m2-empty"><IconCircle><Icon size={24} /></IconCircle><h3>{title}</h3><p>{text}</p>{action && <Button onClick={action}>{actionLabel}</Button>}</Card>;

  const useQuerySection = (param, fallback, allowed) => {
    const read = () => { const value = routeParam(param, fallback); return allowed.includes(value) ? value : fallback; };
    const [value, setValue] = useState(read);
    useEffect(() => { const sync = () => setValue(read()); global.addEventListener('popstate', sync); return () => global.removeEventListener('popstate', sync); }, [param, fallback]);
    const change = useCallback((next, options = {}) => {
      if (!allowed.includes(next)) return;
      setValue(next);
      const url = new URL(location.href);
      next === fallback ? url.searchParams.delete(param) : url.searchParams.set(param, next);
      history[options.replace ? 'replaceState' : 'pushState']({ [param]: next }, '', url);
    }, [param, fallback]);
    return [value, change];
  };

  const FunctionalModal = ({ title, children, onClose }) => {
    const closeRef = useRef(null);
    useEffect(() => { const previous = document.activeElement; const key = event => { if (event.key === 'Escape') onClose(); }; document.addEventListener('keydown', key); closeRef.current?.focus(); return () => { document.removeEventListener('keydown', key); previous?.focus?.(); }; }, [onClose]);
    return <><button type="button" className="m2-scrim" aria-label="Cerrar diálogo" onClick={onClose}/><section className="m2-functional-modal" role="dialog" aria-modal="true" aria-labelledby="m2-modal-title"><header><h2 id="m2-modal-title">{title}</h2><button type="button" ref={closeRef} aria-label="Cerrar" onClick={onClose}><X/></button></header>{children}</section></>;
  };

  const ActionCenter = ({ action, onClose, data, handlers, notify }) => {
    if (!action) return null;
    if (action.type === 'habit' && handlers.HabitForm) {
      const HabitForm = handlers.HabitForm;
      return <FunctionalModal title="Nuevo hábito" onClose={onClose}><HabitForm
        categories={handlers.habitCategories}
        onCreateCategory={handlers.onCreateHabitCategory}
        onCancel={onClose}
        onSave={habit => {
          handlers.onAddHabit({ ...habit, id: uid('habit'), createdAt: habit.createdAt || isoDate(), updatedAt: new Date().toISOString() });
          notify('Hábito creado y sincronizado');
          onClose();
        }}
      /></FunctionalModal>;
    }
    const submit = event => {
      event.preventDefault();
      const fields = Object.fromEntries(new FormData(event.currentTarget));
      if (action.type === 'task') handlers.onUpdateAgenda(fields.date, rows => [...rows, { id: uid('task'), text: fields.name.trim(), dueDate: fields.date, startTime: fields.time, category: fields.category, completed: false, updatedAt: new Date().toISOString() }]);
      if (action.type === 'habit') handlers.onAddHabit({ id: uid('habit'), name: fields.name.trim(), category: fields.category, markColor: fields.color, active: true, schedule: { type: 'daily' }, reminders: [], createdAt: new Date().toISOString() });
      if (action.type === 'expense') handlers.onUpdateFinance(prev => ({ ...prev, transactions: [...(prev.transactions || []), { id: uid('tx'), type: 'expense', amount: Number(fields.amount), accountId: fields.account, category: fields.category, note: fields.note.trim(), date: fields.date, updatedAt: new Date().toISOString() }], accounts: (prev.accounts || []).map(account => account.id === fields.account ? { ...account, balance: Number(account.balance || 0) - Number(fields.amount) } : account) }));
      if (action.type === 'goal') handlers.onUpdateDreamGoals(prev => [...(prev || []), { id: uid('goal'), title: fields.name.trim(), target: Number(fields.target), current: 0, image: fields.image.trim(), icon: '🎯', createdAt: new Date().toISOString() }]);
      if (action.type === 'routine') handlers.onUpdateWorkout(prev => ({ ...prev, routines: [...(prev.routines || []), { id: uid('routine'), name: fields.name.trim(), exercises: [], createdAt: new Date().toISOString() }], updatedAt: new Date().toISOString() }));
      if (action.type === 'account') handlers.onUpdateFinance(prev => ({ ...prev, accounts: [...(prev.accounts || []), { id: uid('account'), name: fields.name.trim(), type: fields.kind, currency: 'COP', balance: Number(fields.balance || 0) }] }));
      if (action.type === 'category') handlers.onUpdateFinance(prev => ({ ...prev, categories: [...(prev.categories || []), { id: uid('category'), name: fields.name.trim(), color: fields.color, type: fields.kind }] }));
      if (action.type === 'contribute') handlers.onUpdateDreamGoals(prev => (prev || []).map(goal => goal.id === action.goal.id ? { ...goal, current: Math.min(Number(goal.target || 0), Number(goal.current || 0) + Number(fields.amount || 0)), updatedAt: new Date().toISOString() } : goal));
      notify('Cambios guardados y sincronizados'); onClose();
    };
    const forms = {
      task: <><label>Nombre<input name="name" required autoFocus/></label><label>Fecha<input name="date" type="date" required defaultValue={isoDate()}/></label><label>Hora<input name="time" type="time" required defaultValue="09:00"/></label><label>Calendario<select name="category"><option>Personal</option><option>Trabajo</option><option>Salud</option></select></label></>,
      expense: <><label>Monto<input name="amount" type="number" min="0.01" step="0.01" required autoFocus/></label><label>Cuenta<select name="account" required>{(data.financeData?.accounts || []).map(item => <option key={item.id} value={item.id}>{item.name}</option>)}</select></label><label>Categoría<select name="category">{(data.financeData?.categories || []).map(item => <option key={item.id} value={item.id}>{item.name}</option>)}</select></label><label>Fecha<input name="date" type="date" defaultValue={isoDate()} required/></label><label>Nota<input name="note"/></label></>,
      goal: <><label>Meta<input name="name" required autoFocus/></label><label>Objetivo<input name="target" type="number" min="1" required/></label><label>Imagen<input name="image" type="url"/></label></>,
      routine: <label>Nombre de la rutina<input name="name" required autoFocus/></label>,
      account: <><label>Nombre<input name="name" required autoFocus/></label><label>Tipo<select name="kind"><option value="cash">Efectivo</option><option value="bank">Banco</option><option value="savings">Ahorros</option></select></label><label>Saldo inicial<input name="balance" type="number" step="0.01" defaultValue="0"/></label></>,
      category: <><label>Nombre<input name="name" required autoFocus/></label><label>Tipo<select name="kind"><option value="expense">Gasto</option><option value="income">Ingreso</option></select></label><label>Color<input name="color" type="color" defaultValue="#f3132b"/></label></>,
      contribute: <label>Aporte para {action.goal?.title}<input name="amount" type="number" min="1" max={Math.max(1, Number(action.goal?.target || 0) - Number(action.goal?.current || 0))} required autoFocus/></label>
    };
    const titles = { task: 'Nueva tarea', habit: 'Nuevo hábito', expense: 'Nuevo gasto', goal: 'Nueva meta', routine: 'Nueva rutina', account: 'Nueva cuenta', category: 'Nueva categoría', contribute: 'Registrar aporte' };
    return <FunctionalModal title={titles[action.type]} onClose={onClose}><form className="m2-action-form" onSubmit={submit}>{forms[action.type]}<footer><Button secondary onClick={onClose}>Cancelar</Button><Button type="submit">Guardar</Button></footer></form></FunctionalModal>;
  };

  const MobileV2Header = ({ userName, streak, avatarUrl, onProfile }) => {
    const [imageFailed, setImageFailed] = useState(false);
    const compact = global.matchMedia('(max-width: 350px)').matches;
    const dateLabel = new Date().toLocaleDateString('es-CO', { weekday: compact ? 'short' : 'long', day: 'numeric', month: 'long' });
    const generatedAvatar = `data:image/svg+xml,${encodeURIComponent('<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64"><rect width="64" height="64" rx="32" fill="#17191d"/><circle cx="32" cy="25" r="12" fill="#f3132b"/><path d="M12 58c2-14 10-21 20-21s18 7 20 21" fill="#f3132b"/><circle cx="28" cy="23" r="2" fill="white"/><circle cx="36" cy="23" r="2" fill="white"/></svg>')}`;
    const avatarSrc = avatarUrl || generatedAvatar;
    return <header className="m2-header" data-testid="mobile-v2-header">
      <div className="m2-date"><CalendarDays size={19} /><span>{dateLabel}</span></div>
      <div className="m2-header-actions">
        <span className="m2-streak" aria-label={`${streak} días de racha`}><Flame size={21} /><b>{streak}</b></span>
        <button type="button" className="m2-avatar" aria-label="Abrir perfil" onClick={onProfile}>
          {!imageFailed ? <img src={avatarSrc} alt="" onError={() => setImageFailed(true)}/> : <span>{initials(userName)}</span>}
        </button>
      </div>
    </header>;
  };

  const PRIMARY_NAV = [
    { id: 'dashboard', label: 'Inicio', icon: Home },
    { id: 'habits', label: 'Hábitos', icon: Target },
    { id: 'agenda', label: 'Agenda', icon: CalendarDays },
    { id: 'finance', label: 'Finanzas', icon: WalletCards }
  ];
  const MORE_NAV = [
    { id: 'workout', label: 'Entreno', icon: Dumbbell },
    { id: 'pomodoro', label: 'Pomodoro', icon: Timer },
    { id: 'dreams', label: 'Metas', icon: Sparkles },
    { id: 'health', label: 'Salud', icon: HeartPulse },
    { id: 'settings', label: 'Configuración', icon: Settings },
    { id: 'creator', label: 'Creador', icon: Award }
  ];

  const MobileV2MoreSheet = ({ open, view, onClose, onNavigate, creatorAccess }) => {
    useEffect(() => { if (!open) return; const key = event => { if (event.key === 'Escape') onClose(); }; document.addEventListener('keydown', key); return () => document.removeEventListener('keydown', key); }, [open, onClose]);
    if (!open) return null;
    const items = creatorAccess ? MORE_NAV : MORE_NAV.filter(item => item.id !== 'creator');
    return <><button className="m2-scrim" onClick={onClose} aria-label="Cerrar menú" /><section className="m2-more-sheet" role="dialog" aria-modal="true" data-testid="mobile-v2-more-sheet"><i className="m2-sheet-handle" /><header><div><span>HabitFlow</span><h2>Más secciones</h2></div><button onClick={onClose} aria-label="Cerrar"><X size={22} /></button></header><div className="m2-more-grid">{items.map(item => <button key={item.id} className={view === item.id ? 'is-active' : ''} onClick={() => { onNavigate(item.id); onClose(); }}><item.icon size={25} /><span>{item.label}</span></button>)}</div></section></>;
  };

  const MobileV2BottomNav = ({ view, onNavigate, moreOpen, onToggleMore, workoutActive = false }) => {
    const moreActive = MORE_NAV.some(item => item.id === view);
    const items = workoutActive ? [PRIMARY_NAV[0], PRIMARY_NAV[1], { id: 'workout', label: 'Entreno', icon: Dumbbell }, PRIMARY_NAV[3]] : PRIMARY_NAV;
    return <nav className="m2-bottom-nav" aria-label="Navegación principal" data-testid="mobile-v2-bottom-nav">{items.map(item => <button type="button" key={item.id} aria-current={view === item.id ? 'page' : undefined} className={view === item.id ? 'is-active' : ''} onClick={() => onNavigate(item.id)}><item.icon size={24} /><span>{item.label}</span></button>)}<button type="button" aria-expanded={moreOpen} className={moreOpen || moreActive ? 'is-active' : ''} onClick={onToggleMore}><MoreHorizontal size={25} /><span>Más</span></button></nav>;
  };

  const ProgressRing = ({ value = 0, label = 'Completado hoy', size = 104 }) => <div className="m2-ring" style={{ '--m2-progress': `${Math.max(0, Math.min(100, value))}%`, width: size, height: size }}><strong>{Math.round(value)}%</strong><span>{label}</span></div>;

  const SharedCapture = () => {
    const [open,setOpen]=useState(false); const [command,setCommand]=useState('');
    const submit=event=>{event?.preventDefault?.();if(!command.trim())return;global.dispatchEvent(new CustomEvent('habitflow-open-shared-capture',{detail:{text:command.trim()}}));setCommand('');setOpen(false)};
    const voice=()=>{global.dispatchEvent(new CustomEvent('habitflow-open-shared-capture',{detail:{voice:true}}));setOpen(false)};
    return <><div className="m2-capture-shell"><button className="m2-capture" onClick={()=>setOpen(true)}><Sparkles size={22}/><span>Captura algo rápido... tarea, hábito, gasto o evento</span></button><button className="m2-capture-mic" aria-label="Dictar captura rápida" onClick={voice}><Mic/></button></div>{open&&<FunctionalModal title="Captura rápida" onClose={()=>setOpen(false)}><form className="m2-shared-capture" onSubmit={submit}><label>¿Qué quieres registrar?<textarea autoFocus value={command} onChange={event=>setCommand(event.target.value)} onKeyDown={event=>{if(event.key==='Enter'&&!event.shiftKey){event.preventDefault();submit(event)}}} placeholder="Ej.: Gasté 20.000 pesos en comida con Bancolombia"/></label><p>Usa el mismo intérprete de Agenda, Hábitos y Finanzas. Podrás revisar todo antes de guardar.</p><footer><Button secondary onClick={voice}><Mic/>Dictar</Button><Button type="submit" disabled={!command.trim()}><ArrowUp/>Interpretar</Button></footer></form></FunctionalModal>}</>;
  };

  const QuickPomodoroCard = ({ data, onUpdateUser, onUpdatePomodoro, onComplete, navigate }) => {
    const settings=data.user?.pomodoro||{focus:25,shortBreak:5,longBreak:15}; const saved=data.user?.quickPomodoro||{};
    const baseDuration=Math.max(1,Number(saved.duration||settings.focus||25)); const [clock,setClock]=useState(Date.now()); const [showSettings,setShowSettings]=useState(false); const [local,setLocal]=useState(settings); const completionRef=useRef('');
    const running=!!saved.running&&Number(saved.endAt)>Date.now(); const remaining=running?Math.max(0,Math.ceil((Number(saved.endAt)-clock)/1000)):Math.max(0,Number(saved.remaining??baseDuration*60));
    const persist=patch=>onUpdateUser({quickPomodoro:{duration:baseDuration,remaining,...saved,...patch,updatedAt:new Date().toISOString()}});
    useEffect(()=>{if(!saved.running)return;const id=setInterval(()=>setClock(Date.now()),1000);return()=>clearInterval(id)},[saved.running,saved.endAt]);
    useEffect(()=>{if(!saved.running||Number(saved.endAt)>clock)return;const key=String(saved.endAt);if(completionRef.current===key)return;completionRef.current=key;persist({running:false,endAt:null,remaining:baseDuration*60});onUpdatePomodoro(prev=>[...(prev||[]),{id:uid('pomodoro'),date:isoDate(),completedAt:new Date().toISOString(),focusTime:baseDuration,source:'mobile-home'}]);onComplete?.(baseDuration)},[clock,saved.running,saved.endAt]);
    const choose=value=>persist({duration:value,remaining:value*60,running:false,endAt:null}); const start=()=>persist({running:true,endAt:Date.now()+Math.max(1,remaining)*1000}); const pause=()=>persist({running:false,endAt:null,remaining}); const reset=()=>persist({running:false,endAt:null,remaining:baseDuration*60});
    const saveSettings=()=>{onUpdateUser({pomodoro:{...settings,...local}});if(!saved.running)persist({duration:Number(local.focus),remaining:Number(local.focus)*60});setShowSettings(false)};
    return <><Card className="m2-pomodoro-mini"><header><h2><Timer size={20}/>Pomodoro rápido</h2><button aria-label="Configurar Pomodoro rápido" onClick={()=>{setLocal(settings);setShowSettings(true)}}><Settings size={18}/></button></header><strong>{minutes(remaining)}</strong><div className="m2-duration-row">{[25,15,50].map(value=><button onClick={()=>choose(value)} className={baseDuration===value?'is-active':''} key={value}>{value} min</button>)}</div><div className="m2-pomo-quick-actions"><Button onClick={running?pause:start}>{running?<Pause/>:<Play/>}{running?'Pausar':remaining<baseDuration*60?'Reanudar':'Iniciar'}</Button><button aria-label="Reiniciar Pomodoro" onClick={reset}><RefreshCcw/></button></div><button className="m2-open-pomodoro" onClick={()=>navigate('pomodoro')}>Abrir Pomodoro completo</button></Card>{showSettings&&<FunctionalModal title="Configurar Pomodoro" onClose={()=>setShowSettings(false)}><div className="m2-pomo-quick-settings">{[['focus','Enfoque',1,120],['shortBreak','Descanso corto',1,30],['longBreak','Descanso largo',5,60]].map(([key,label,min,max])=><label key={key}>{label}<input type="number" min={min} max={max} value={local[key]} onChange={event=>setLocal(current=>({...current,[key]:Math.max(min,Math.min(max,Number(event.target.value)||min))}))}/></label>)}<label className="m2-toggle-label">Sonido al finalizar<input type="checkbox" checked={local.soundEnabled!==false} onChange={event=>setLocal(current=>({...current,soundEnabled:event.target.checked}))}/></label><label className="m2-toggle-label">Alerta visual<input type="checkbox" checked={local.alertEnabled!==false} onChange={event=>setLocal(current=>({...current,alertEnabled:event.target.checked}))}/></label><label>Modo de enfoque<select value={local.focusMode||'standard'} onChange={event=>setLocal(current=>({...current,focusMode:event.target.value}))}><option value="standard">Estándar</option><option value="distraction-free">Sin distracciones</option></select></label><footer><Button secondary onClick={()=>setShowSettings(false)}>Cancelar</Button><Button onClick={saveSettings}>Guardar configuración</Button></footer></div></FunctionalModal>}</>;
  };

  const HomePage = ({ data, navigate, openAction, streak, onCompleteHabit, onUpdateAgenda, onUpdateUser, onUpdatePomodoro, onQuickPomodoroComplete }) => {
    const habits=activeHabits(data); const today=isoDate(); const allAgenda=data.agenda?.[today]||[]; const agenda=allAgenda.slice(0,3); const doneHabits=habits.filter(habit=>recordsFor(data,habit.id,today)).length; const completedTasks=allAgenda.filter(item=>item.completed).length; const pct=habits.length+allAgenda.length?Math.round((doneHabits+completedTasks)/(habits.length+allAgenda.length)*100):0; const pending=habits.filter(habit=>!recordsFor(data,habit.id,today)).slice(0,3);
    const finance=data.financeData||{}; const rate=Math.max(1,Number(finance.copRate||4000)); const currency=finance.currency||'COP'; const tx=(finance.transactions||[]).filter(item=>item.category!=='transfer'); const month=today.slice(0,7); const expenses=tx.filter(item=>item.type==='expense'); const toDisplay=amount=>currency==='COP'?Number(amount||0)*rate:Number(amount||0); const todaySpend=expenses.filter(item=>item.date===today).reduce((sum,item)=>sum+toDisplay(item.amount),0); const monthSpend=expenses.filter(item=>String(item.date||'').startsWith(month)).reduce((sum,item)=>sum+toDisplay(item.amount),0); const budget=toDisplay(finance.monthlyBudget||0); const budgetPct=budget?Math.min(100,Math.round(monthSpend/budget*100)):0; const days=Array.from({length:7},(_,index)=>{const date=new Date();date.setDate(date.getDate()-(6-index));return isoDate(date)}); const chart=days.map(date=>expenses.filter(item=>item.date===date).reduce((sum,item)=>sum+toDisplay(item.amount),0)); const maxChart=Math.max(1,...chart); const byCategory=expenses.filter(item=>item.date===today).reduce((map,item)=>{map[item.category]=(map[item.category]||0)+toDisplay(item.amount);return map},{}); const topCategory=Object.entries(byCategory).sort((a,b)=>b[1]-a[1])[0]; const categoryInfo=finance.categories?.find(item=>item.id===topCategory?.[0]);
    let xp=Number(data.user?.xp||0),level=1,needed=Math.round(100*level*1.5);while(xp>=needed){xp-=needed;level+=1;needed=Math.round(100*level*1.5)}const xpPct=needed?Math.round(xp/needed*100):0;
    return <div className="m2-page m2-home-page"><div className="m2-hero-row"><div><h1>Buenas tardes, <em>{data.user?.name||'Usuario'}.</em></h1><p>Mantén el enfoque. Pequeñas acciones, grandes resultados.</p></div><ProgressRing value={pct} size={64}/></div><SharedCapture/>
      <div className="m2-quick-grid">{[['task','Nueva tarea',CalendarDays],['pomodoro','Pomodoro',Timer],['habit','Nuevo hábito',Target],['expense','Nuevo gasto',WalletCards]].map(([id,label,Icon])=><button key={id} onClick={()=>id==='pomodoro'?document.querySelector('.m2-pomodoro-mini')?.scrollIntoView({behavior:'smooth',block:'center'}):openAction(id)}><Icon size={27}/><span>{label}</span></button>)}</div>
      <div className="m2-home-grid">
        <Card className="m2-list-card"><header><h2><CalendarDays size={20}/>Plan del día</h2><button onClick={()=>navigate('agenda')}>Ver todo</button></header>{agenda.length?agenda.map(item=><div className="m2-line" key={item.id}><button aria-label={`${item.completed?'Descompletar':'Completar'} ${item.text||item.title}`} onClick={()=>onUpdateAgenda(today,rows=>rows.map(row=>row.id===item.id?{...row,completed:!row.completed}:row))}>{item.completed?<CheckCircle2 size={19}/>:<Circle size={19}/>}</button><button className="m2-line-title" onClick={()=>navigate('agenda')}>{item.text||item.title}</button><small>{item.startTime||item.dueTime||'Hoy'}</small></div>):<p className="m2-muted">Tu plan está despejado.</p>}</Card>
        <Card className="m2-list-card"><header><h2><RefreshCcw size={20}/>Hábitos pendientes</h2><button onClick={()=>navigate('habits')}>Ver todo</button></header>{pending.length?pending.map((habit,index)=><div className="m2-line" key={habit.id}><button aria-label={`Completar ${habit.name}`} onClick={()=>onCompleteHabit(habit.id)}><IconCircle tone={['green','amber','blue'][index]||'red'}><Target size={18}/></IconCircle></button><button className="m2-line-title" onClick={()=>navigate('habits')}>{habit.name}</button><small>0/1</small></div>):<p className="m2-muted">Todos los hábitos están listos.</p>}<button className="m2-link" onClick={()=>openAction('habit')}><Plus size={16}/>Añadir hábito</button></Card>
        <QuickPomodoroCard data={data} onUpdateUser={onUpdateUser} onUpdatePomodoro={onUpdatePomodoro} onComplete={onQuickPomodoroComplete} navigate={navigate}/>
        <Card className="m2-finance-mini"><header><h2><WalletCards size={20}/>Finanzas rápidas</h2><button onClick={()=>navigate('finance')}>Ver todo</button></header><span>Gasto del día</span><strong>{money(todaySpend,currency)}</strong><div className="m2-real-sparkline" aria-label="Gastos de los últimos siete días">{chart.map((value,index)=><i key={days[index]} style={{height:`${Math.max(5,value/maxChart*100)}%`}}/>)}</div><button className="m2-budget-summary" onClick={()=>navigate('finance')}><span>Presupuesto mensual</span><b>{money(monthSpend,currency)} / {money(budget,currency)}</b><em>{budgetPct}%</em><i className="m2-progress"><b style={{width:`${budgetPct}%`}}/></i></button><button className="m2-category-summary" disabled={!topCategory} onClick={()=>navigate('finance',{params:{wallet:'movements',category:topCategory?.[0]}})}><span>Categoría principal<strong>{categoryInfo?.name||categoryInfo?.label||'Sin gastos hoy'}</strong></span><b>{topCategory?money(topCategory[1],currency):money(0,currency)}</b></button></Card>
        <Card className="m2-xp-card"><header><span>Nivel {data.user?.level||level}</span><small>{data.user?.xp||0} XP</small></header><button onClick={()=>navigate('habits')}><Medal size={42}/><span><strong>Camino imparable</strong><small>{xp} / {needed} XP</small><i className="m2-progress"><b style={{width:`${xpPct}%`}}/></i></span></button></Card>
        <Card className="m2-achievement"><header><h2>Logros recientes</h2><button onClick={()=>navigate('habits')}>Ver todos</button></header><button onClick={()=>navigate('habits')}><Trophy size={40}/><span><strong>Racha de fuego</strong><small>{streak} días consecutivos</small></span></button></Card>
      </div>
    </div>;
  };

  const HabitsPage = ({ data, onCompleteHabit, hydration, onToggleHydrationWidget, openAction }) => {
    const [period, setPeriod] = useState('week');
    const [offset, setOffset] = useState(0);
    const habits = activeHabits(data).slice(0, 4);
    const dayCount = period === 'week' ? 7 : 28;
    const days = Array.from({ length: dayCount }, (_, index) => { const date = new Date(); date.setDate(date.getDate() + offset * dayCount - (dayCount - 1 - index)); return { date: isoDate(date), label: ['D','L','M','M','J','V','S'][date.getDay()] }; });
    const completed = habits.reduce((sum, habit) => sum + days.filter(day => recordsFor(data, habit.id, day.date)).length, 0);
    const pct = habits.length ? Math.round(completed / (habits.length * 7) * 100) : 0;
    return <div className="m2-page"><PageTitle title="Mis hábitos" subtitle="Pequeños hábitos, grandes cambios." action={<div className="m2-title-actions"><Tabs value={period} onChange={value => { setPeriod(value); setOffset(0); }} items={[{id:'week',label:'Semanal'},{id:'month',label:'Mensual'}]} /><Button onClick={() => openAction('habit')}><Plus/>Nuevo hábito</Button></div>} />
      <div className="m2-metrics-3"><Card><IconCircle><Activity/></IconCircle><strong>{habits.length}</strong><span>Hábitos activos</span></Card><Card><ProgressRing value={pct} size={82}/><span>Cumplimiento<br/>semanal</span></Card><Card><IconCircle><Flame/></IconCircle><strong>{Math.max(0, ...habits.map(h => Number(h.streak || 0)))}</strong><span>Racha global<br/>días</span></Card></div>
      <Card className={`m2-habit-table ${period === 'month' ? 'is-month' : ''}`}><header><h2>{period === 'week' ? 'Vista semanal' : 'Vista mensual'}</h2><span>{shortDate(days[0].date)} – {shortDate(days[days.length - 1].date)}</span><div><button aria-label="Período anterior" onClick={() => setOffset(value => value - 1)}><ChevronLeft/></button><button aria-label="Período siguiente" disabled={offset >= 0} onClick={() => setOffset(value => Math.min(0, value + 1))}><ChevronRight/></button></div></header><div className="m2-habit-head"><span/><span>{days.slice(period === 'week' ? 0 : -7).map(day => <b key={day.date}>{day.label}</b>)}</span></div>{habits.length ? habits.map((habit,index) => <div className="m2-habit-row" key={habit.id}><div><IconCircle tone={['blue','amber','green','purple'][index]}>{index===0?<Droplet/>:index===1?<BookOpen/>:index===2?<Activity/>:<Sparkles/>}</IconCircle><span>{habit.name}</span></div><div>{days.slice(period === 'week' ? 0 : -7).map(day => {const done=recordsFor(data,habit.id,day.date);const future=day.date>isoDate();return <button aria-label={`${habit.name} ${day.date}`} disabled={future} key={day.date} className={done?'is-done':''} onClick={() => onCompleteHabit(habit.id,day.date)}>{done?<Check/>:<Circle/>}</button>})}</div></div>) : <Empty title="Aún no tienes hábitos" text="Crea tu primer hábito para construir constancia." action={() => openAction('habit')} actionLabel="Nuevo hábito"/>}<footer>{habits.map((habit,index)=><span key={habit.id}><i className={`tone-${['blue','amber','green','purple'][index]}`}/>{habit.name}</span>)}</footer></Card>
      <Card className="m2-widget-toggle"><IconCircle><Droplet/></IconCircle><div><h3>Widget de hidratación</h3><p>Muestra tu progreso de hidratación en la barra lateral / utilidades de la app.</p></div><button role="switch" aria-checked={hydration.widgetEnabled} aria-label="Mostrar widget de hidratación" className={hydration.widgetEnabled?'is-on':''} onClick={() => onToggleHydrationWidget(!hydration.widgetEnabled)}><i/></button></Card>
    </div>;
  };

  const PomodoroPage = ({ data, onUpdatePomodoro, onUpdateUser, onUpdateAgenda, openAction }) => {
    const saved = data.user?.pomodoro || {}; const today = isoDate(); const tasks = (data.agenda?.[today] || []).filter(item => !item.completed).slice(0,4);
    const [mode,setMode]=useState(saved.mobileMode || 'focus'); const [duration,setDuration]=useState(Number(saved.mobileDuration || 25)); const [seconds,setSeconds]=useState(Number(saved.mobileSeconds || 25*60)); const [running,setRunning]=useState(false); const [notes,setNotes]=useState(saved.mobileNotes || ''); const [sound,setSound]=useState(saved.soundEnabled !== false); const [showInfo,setShowInfo]=useState(true);
    useEffect(()=>{onUpdateUser({pomodoro:{...saved,mobileMode:mode,mobileDuration:duration,mobileSeconds:seconds,mobileNotes:notes,soundEnabled:sound}})},[mode,duration,notes,sound]);
    useEffect(()=>{if(!running)return;const id=setInterval(()=>setSeconds(current=>{if(current>1)return current-1;setRunning(false);onUpdatePomodoro(prev=>[...(prev||[]),{id:uid('pomodoro'),date:isoDate(),minutes:duration,mode,completedAt:new Date().toISOString()}]);return duration*60}),1000);return()=>clearInterval(id)},[running,duration,mode,onUpdatePomodoro]);
    const selectDuration=(value)=>{setDuration(value);setSeconds(value*60);setRunning(false)};
    const selectMode = value => { setMode(value); selectDuration(value === 'focus' ? 25 : value === 'break' ? 5 : 15); };
    return <div className="m2-page m2-pomodoro-page"><Card className="m2-pomo-main"><Tabs value={mode} onChange={selectMode} items={[{id:'focus',label:'Enfoque',icon:Target},{id:'break',label:'Descanso',icon:Clock3},{id:'long',label:'Largo',icon:Moon}]} /><div className="m2-timer-ring"><span>{mode==='focus'?'Enfoque':mode==='break'?'Descanso':'Descanso largo'}</span><strong>{minutes(seconds)}</strong><small>{running ? 'Sesión en curso' : 'Listo para comenzar'}</small></div><div className="m2-timer-controls"><button aria-label="Pausar" disabled={!running} onClick={()=>setRunning(false)}><Pause/></button><button aria-label={running?'Pausar sesión':'Iniciar sesión'} className="is-primary" onClick={()=>setRunning(v=>!v)}>{running?<Pause/>:<Play/>}</button><button aria-label="Reiniciar" onClick={()=>{setRunning(false);setSeconds(duration*60)}}><RefreshCcw/></button></div><div className="m2-duration-row">{[25,15,50].map(value=><button className={duration===value?'is-active':''} onClick={()=>selectDuration(value)} key={value}>{value} min</button>)}</div><Card className="m2-pomo-settings"><button onClick={()=>setSound(value=>!value)}><Bell/><span><small>Sonido</small>{sound?'Campana activa':'Silenciado'}</span><ChevronRight/></button><button onClick={()=>setShowInfo(value=>!value)}><Target/><span><small>Modo de enfoque</small>{showInfo?'Sin distracciones':'Estándar'}</span><ChevronRight/></button></Card></Card>
      <Card className="m2-toggle-line"><IconCircle><Bell/></IconCircle><div><h3>Alerta sonora al finalizar</h3><p>También avisar al iniciar descansos</p></div><button role="switch" aria-checked={sound} aria-label="Alerta sonora" className={sound?'is-on':''} onClick={()=>setSound(v=>!v)}><i/></button></Card>{showInfo&&<Card className="m2-alert-line"><IconCircle><Bell/></IconCircle><span>Cuando finalice el tiempo, verás una alerta en pantalla completa.</span><button aria-label="Ocultar aviso" onClick={()=>setShowInfo(false)}><X/></button></Card>}
      <div className="m2-pomo-bottom"><Card><header><h2><FileText/>Notas del pomodoro</h2></header><textarea value={notes} onChange={event=>setNotes(event.target.value)} maxLength={300} placeholder="Escribe tus notas aquí..."/><small>{notes.length} / 300 · guardado automático</small></Card><Card><header><h2><CheckCircle2/>Pendientes del pomodoro</h2><b>{tasks.length}</b></header>{tasks.map(item=><label key={item.id}><input type="checkbox" checked={!!item.completed} onChange={()=>onUpdateAgenda(today,rows=>rows.map(row=>row.id===item.id?{...row,completed:!row.completed}:row))}/>{item.text||item.title}</label>)}{!tasks.length&&<p className="m2-muted">No hay tareas pendientes.</p>}<button onClick={()=>openAction('task')}><Plus/>Añadir tarea rápida...</button></Card></div>
    </div>;
  };

  const agendaTone = (index) => ['green','blue','red','purple','amber'][index%5];
  const AgendaItem = ({ item,index,onActivate }) => <Card as="button" type="button" onClick={onActivate} className={`m2-agenda-item tone-${agendaTone(index)}`}><IconCircle tone={agendaTone(index)}>{index%5===0?<Activity/>:index%5===1?<BookOpen/>:index%5===2?<Target/>:index%5===3?<Sparkles/>:<Clock3/>}</IconCircle><div><strong>{item.text||item.title||'Evento'}</strong><span>{item.category||'Personal'} · {item.startTime||item.dueTime||'Todo el día'}{item.endTime?` – ${item.endTime}`:''}</span></div>{item.completed?<CheckCircle2/>:<ChevronRight/>}</Card>;

  const AgendaPage = ({ data, onUpdateAgenda, openAction }) => {
    const [section,change]=useQuerySection('agenda','week',['week','month','list','upcoming']); const [filters,setFilters]=useState(false); const [range,setRange]=useState('seven'); const [filter,setFilter]=useState('Todos'); const [cursor,setCursor]=useState(0);
    const items=allAgendaItems(data.agenda).sort((a,b)=>`${a.date}${a.startTime||''}`.localeCompare(`${b.date}${b.startTime||''}`)); const today=isoDate(); const upcoming=items.filter(item=>item.date>=today).slice(0,8);
    const activate=item=>onUpdateAgenda(item.date,rows=>rows.map(row=>row.id===item.id?{...row,completed:!row.completed}:row));
    const tabs=[{id:'day',label:'Día'},{id:'week',label:'Semana'},{id:'month',label:'Mes'},{id:'list',label:'Agenda'}];
    if(section==='upcoming')return <div className="m2-page"><PageTitle title="Próximos eventos" subtitle="Todo lo que viene en los próximos días." action={<button className="m2-back" aria-label="Volver a Agenda" onClick={()=>change('list')}><ArrowLeft/></button>}/><Tabs value={range} onChange={setRange} items={[{id:'today',label:'Hoy'},{id:'tomorrow',label:'Mañana'},{id:'seven',label:'7 días'},{id:'month',label:'Mes'}]}/><Card className="m2-upcoming-summary"><IconCircle><CalendarDays/></IconCircle><strong>{upcoming.length}</strong><span>eventos próximos<br/><small>En el rango elegido</small></span><hr/><IconCircle><Target/></IconCircle><strong>{Math.min(3,upcoming.length)}</strong><span>prioridades<br/><small>Eventos clave</small></span></Card><div className="m2-agenda-list">{upcoming.map((item,index)=><AgendaItem key={item.id||index} item={item} index={index} onActivate={()=>activate(item)}/>)}</div></div>;
    return <div className="m2-page"><PageTitle title="Agenda" subtitle={section==='month'?'Organiza tu mes y mantén el enfoque.':section==='list'?'Todo tu calendario en una lista clara.':'Organiza tu semana y mantén el enfoque.'}/><Tabs value={section==='list'?'list':section} onChange={id=>change(id==='day'?'week':id)} items={tabs}/><div className="m2-agenda-toolbar"><button aria-label="Período anterior" onClick={()=>setCursor(value=>value-1)}><ChevronLeft/></button><strong><CalendarDays/> {section==='month'?'Mes seleccionado':section==='list'?'Todos los eventos':`Semana ${cursor===0?'actual':cursor}`}</strong><button aria-label="Período siguiente" onClick={()=>setCursor(value=>value+1)}><ChevronRight/></button>{section==='list'&&<Button onClick={()=>openAction('task')}><Plus/>Nueva tarea</Button>}<button className="m2-filter" onClick={()=>setFilters(true)}><ListFilter/>Filtros</button></div>
      {section==='week'&&<><Card className="m2-week-days">{['L 13','M 14','M 15','J 16','V 17','S 18','D 19'].map((day,index)=><span className={index===1?'is-today':''} key={day}>{day.split(' ')[0]}<b>{day.split(' ')[1]}</b><i/></span>)}</Card><Card className="m2-week-grid"><div className="m2-hours">{['07','09','11','13','15','17','19','21'].map(h=><span key={h}>{h}:00</span>)}</div>{Array.from({length:7},(_,day)=><div className="m2-day-column" key={day}>{upcoming.slice(0,day%3+2).map((item,index)=><span key={item.id||index} className={`tone-${agendaTone(index+day)}`} style={{top:`${index*92+10}px`}}>{item.text||item.title||'Evento'}<small>{item.startTime||'09:00'}</small></span>)}</div>)}</Card><Card className="m2-week-summary"><div><h3><BarChart3/>Resumen semanal</h3><ProgressRing value={84} size={92}/><strong>84% completado</strong></div><div><h3>Próximos eventos</h3>{upcoming.slice(0,2).map((item,index)=><span key={item.id||index}>{item.text||item.title||'Evento'}<small>{item.startTime||'Hoy'}</small></span>)}</div></Card></>}
      {section==='month'&&<><Card className="m2-month-grid">{['L','M','M','J','V','S','D'].map((d,i)=><b key={`${d}${i}`}>{d}</b>)}{Array.from({length:35},(_,i)=><span key={i} className={i===15?'is-today':''}>{i<3?29+i:i-2}<small>{i%2===0&&<i/>}{i%5===0&&<i/>}</small></span>)}</Card><h2 className="m2-section-title">Resumen del mes</h2><div className="m2-metrics-3"><Card><CalendarDays/><strong>{items.length}</strong><span>Eventos</span></Card><Card><Target/><strong>{items.filter(i=>i.completed).length}</strong><span>Completados</span></Card><Card><Clock3/><strong>{items.length*2} h</strong><span>Planificado</span></Card></div><h2 className="m2-section-title">Próximos eventos</h2><div className="m2-agenda-list">{upcoming.slice(0,3).map((item,index)=><AgendaItem key={item.id||index} item={item} index={index} onActivate={()=>activate(item)}/>)}</div></>}
      {section==='list'&&<><div className="m2-chip-row">{['Todos','Trabajo','Personal','Hábitos'].map(value=><button key={value} className={filter===value?'is-active':''} onClick={()=>setFilter(value)}>{value}</button>)}</div><div className="m2-agenda-list"><h2>Hoy <small>· {shortDate(today)}</small></h2>{(upcoming.length?upcoming:items).filter(item=>filter==='Todos'||item.category===filter).map((item,index)=><AgendaItem key={item.id||index} item={item} index={index} onActivate={()=>activate(item)}/>)}</div><Button secondary onClick={()=>change('upcoming')}>Ver próximos eventos</Button></>}
      {filters&&<FunctionalModal title="Filtros" onClose={()=>setFilters(false)}><div className="m2-filter-options"><h3>Calendario</h3><div className="m2-chip-row">{['Todos','Personal','Trabajo','Salud'].map(value=><button className={filter===value?'is-active':''} onClick={()=>setFilter(value)} key={value}>{value}</button>)}</div><footer><Button secondary onClick={()=>setFilter('Todos')}>Limpiar</Button><Button onClick={()=>setFilters(false)}>Aplicar filtros</Button></footer></div></FunctionalModal>}
    </div>;
  };

  const WorkoutTabs = ({ value, onChange }) => <Tabs label="Secciones de Entreno" value={value} onChange={onChange} items={[{id:'summary',label:'Hoy',icon:CalendarDays},{id:'routines',label:'Rutinas',icon:Dumbbell},{id:'library',label:'Biblioteca',icon:BookOpen},{id:'progress',label:'Progreso',icon:TrendingUp}]}/>;
  const WorkoutPage = ({ data, onUpdateWorkout, openAction, notify }) => {
    const [section,change]=useQuerySection('workout','summary',['summary','routines','library','progress','active']);const [catalog,setCatalog]=useState([]);const [search,setSearch]=useState('');const [muscle,setMuscle]=useState('Todos');const [detail,setDetail]=useState(null);const workout=data.workoutData||{};
    useEffect(()=>{if(['summary','library','active'].includes(section))global.HabitFlowExerciseDataset?.loadCatalog().then(items=>setCatalog(items.slice(0,18))).catch(()=>{})},[section]);
    const filteredCatalog=catalog.filter(item=>(muscle==='Todos'||String(item.category||item.body_part||'').toLowerCase().includes(muscle.toLowerCase()))&&String(item.name||'').toLowerCase().includes(search.toLowerCase()));
    const adjustSet=(setIndex,field,delta)=>onUpdateWorkout(prev=>({...prev,activeSession:{...prev.activeSession,exercises:prev.activeSession.exercises.map((item,i)=>i===(prev.activeSession.currentExerciseIndex||0)?{...item,sets:item.sets.map((set,j)=>j===setIndex?{...set,[field]:Math.max(0,Number(set[field]||0)+delta)}:set)}:item)}}));
    const finishSession=()=>onUpdateWorkout(prev=>{const session=prev.activeSession;if(!session)return prev;return {...prev,activeSession:null,sessions:[...(prev.sessions||[]),{...session,status:'completed',completedAt:new Date().toISOString()}],updatedAt:new Date().toISOString()}});
    const start=(routine)=>{const chosen=(routine?.exercises||[]).map((row,index)=>{const ex=catalog.find(item=>String(item.id)===String(row.exerciseId||row.id))||catalog[index]||{};return {exerciseId:ex.id,exerciseName:ex.name||row.name||'Ejercicio',gifUrl:ex.gif_url||'',category:ex.category||'',sets:Array.from({length:Number(row.sets||3)},(_,i)=>({id:uid('set'),setNumber:i+1,reps:Number(String(row.reps||10).match(/\d+/)?.[0]||10),weight:Number(row.weight||0),completed:false}))}});if(!chosen.length&&catalog[0])chosen.push({exerciseId:catalog[0].id,exerciseName:catalog[0].name,gifUrl:catalog[0].gif_url,category:catalog[0].category,sets:Array.from({length:4},(_,i)=>({id:uid('set'),setNumber:i+1,reps:10,weight:0,completed:false}))});const session={id:uid('session'),routineName:routine?.name||'Entreno libre',startedAt:new Date().toISOString(),status:'active',currentExerciseIndex:0,exercises:chosen};onUpdateWorkout(prev=>({...prev,activeSession:session,updatedAt:new Date().toISOString()}));change('active')};
    const media=item=>global.HabitFlowExerciseDataset?.resolveExerciseMedia(item?.image||item?.gif_url||item?.gifUrl)||'';
    if(section==='active'){const session=workout.activeSession;if(!session)return <div className="m2-page"><PageTitle title="Sesión activa" subtitle="Tu entrenamiento se guardará automáticamente." action={<button className="m2-back" onClick={()=>change('summary')} aria-label="Volver"><ArrowLeft/></button>}/><Empty icon={Dumbbell} title="No hay una sesión activa" text="Inicia una rutina para registrar tus series." action={()=>change('routines')} actionLabel="Ver rutinas"/></div>;const current=session.currentExerciseIndex||0;const ex=session.exercises?.[current];const toggleSet=index=>onUpdateWorkout(prev=>({...prev,activeSession:{...prev.activeSession,exercises:prev.activeSession.exercises.map((item,i)=>i===current?{...item,sets:item.sets.map((set,j)=>j===index?{...set,completed:!set.completed}:set)}:item)}}));const next=()=>onUpdateWorkout(prev=>({...prev,activeSession:{...prev.activeSession,currentExerciseIndex:Math.min(prev.activeSession.exercises.length-1,current+1)}}));return <div className="m2-page"><PageTitle title="Sesión activa" subtitle={session.routineName||'Entreno libre'} action={<Card className="m2-session-time"><Dumbbell/>Sesión en progreso<strong>{Math.max(1,Math.round((Date.now()-Date.parse(session.startedAt||Date.now()))/60000))} min</strong></Card>}/><Card className="m2-current-exercise"><div className="m2-workout-media">{media(ex)&&<img src={media(ex)} alt="" loading="lazy"/>}</div><div><span>Ejercicio actual</span><h2>{ex?.exerciseName||'Ejercicio'}</h2><em>{ex?.category||'Entreno'}</em><b><Timer/>Registro automático</b></div></Card><Card className="m2-sets"><header><span>Set</span><span>Peso (kg)</span><span>Reps</span><Check/></header>{(ex?.sets||[]).map((set,index)=><div key={set.id}><strong>{index+1}</strong><span><button aria-label="Restar peso" onClick={()=>adjustSet(index,'weight',-1)}>−</button>{set.weight||0}<button aria-label="Sumar peso" onClick={()=>adjustSet(index,'weight',1)}>+</button></span><span><button aria-label="Restar repetición" onClick={()=>adjustSet(index,'reps',-1)}>−</button>{set.reps||0}<button aria-label="Sumar repetición" onClick={()=>adjustSet(index,'reps',1)}>+</button></span><button aria-label={`Completar serie ${index+1}`} className={set.completed?'is-done':''} onClick={()=>toggleSet(index)}>{set.completed?<Check/>:<Circle/>}</button></div>)}<Button onClick={()=>{const index=(ex?.sets||[]).findIndex(set=>!set.completed);if(index>=0)toggleSet(index)}}><Dumbbell/>Completar set</Button></Card><h2 className="m2-section-title">Siguientes ejercicios</h2><div className="m2-exercise-list">{session.exercises?.slice(current+1,current+4).map((item,index)=><Card as="button" type="button" onClick={next} key={item.exerciseId||index}>{media(item)&&<img src={media(item)} alt="" loading="lazy"/>}<b>{current+index+2}</b><span><strong>{item.exerciseName}</strong><small>{item.category}</small></span><ChevronRight/></Card>)}</div><div className="m2-two-actions"><Button secondary disabled={current<=0} onClick={()=>onUpdateWorkout(prev=>({...prev,activeSession:{...prev.activeSession,currentExerciseIndex:current-1}}))}>Anterior</Button><Button secondary onClick={()=>current<session.exercises.length-1?next():finishSession()}>{current<session.exercises.length-1?'Siguiente':'Finalizar sesión'}</Button></div></div>}
    const routines=workout.routines||[];
    return <div className="m2-page"><PageTitle title="Entreno" subtitle={section==='routines'?'Tus rutinas listas para avanzar.':section==='library'?'Explora ejercicios y encuentra el indicado.':section==='progress'?'Tu evolución, clara y accionable.':'Tu sesión, más clara y potente.'}/><WorkoutTabs value={section} onChange={change}/>
      {section==='summary'&&<><Card className="m2-workout-hero"><div><span><Dumbbell/>Entreno de hoy</span><h2>{routines[0]?.name||'Entreno libre'}</h2><p>{routines[0]?.exercises?.length||0} ejercicios · 60 min</p><Button onClick={()=>start(routines[0])}><Play/>Iniciar sesión</Button></div></Card><div className="m2-chip-row">{['Todos','Pecho','Espalda','Piernas','Hombros'].map(value=><button className={muscle===value?'is-active':''} onClick={()=>setMuscle(value)} key={value}>{value}</button>)}</div><Card className="m2-active-routine"><IconCircle><Dumbbell/></IconCircle><div><small>Rutina activa</small><strong>{routines[0]?.name||'Entreno libre'}</strong><span>{routines[0]?.exercises?.length||0} ejercicios · 60 min</span></div><Button secondary onClick={()=>change('routines')}>Gestionar rutinas</Button></Card><h2 className="m2-section-title">Biblioteca de ejercicios</h2><div className="m2-exercise-list">{filteredCatalog.slice(0,4).map(item=><Card as="button" type="button" onClick={()=>setDetail(item)} key={item.id}>{media(item)&&<img src={media(item)} alt="" loading="lazy"/>}<span><strong>{item.name}</strong><small>{item.category||item.body_part} · {item.equipment}</small></span><ChevronRight/></Card>)}</div></>}
      {section==='routines'&&<><Card className="m2-routines-head"><IconCircle><Dumbbell/></IconCircle><div><h2>Mis rutinas</h2><span>{routines.length} activas</span></div><Button onClick={()=>openAction('routine')}><Plus/>Nueva rutina</Button></Card>{routines.length?<div className="m2-routine-list">{routines.map((routine,index)=><Card key={routine.id}><div className={`m2-routine-photo tone-${agendaTone(index)}`}/><div><h2><Dumbbell/>{routine.name}</h2><p>{routine.exercises?.length||0} ejercicios · 60 min · Intermedio</p><div className="m2-chip-row"><span>{routine.exercises?.length||0} ejercicios</span></div><div className="m2-two-actions"><Button onClick={()=>start(routine)}><Play/>Iniciar</Button><Button secondary onClick={()=>{if(global.confirm(`¿Eliminar ${routine.name}?`))onUpdateWorkout(prev=>({...prev,routines:(prev.routines||[]).filter(item=>item.id!==routine.id)}))}}>Eliminar</Button></div></div></Card>)}</div>:<Empty icon={Dumbbell} title="No hay rutinas guardadas" text="Crea un plan con ejercicios reales del catálogo." action={()=>openAction('routine')} actionLabel="Nueva rutina"/>}</>}
      {section==='library'&&<><div className="m2-search"><Search/><input value={search} onChange={event=>setSearch(event.target.value)} placeholder="Buscar ejercicio, músculo o equipo"/></div><div className="m2-chip-row">{['Todos','Pecho','Espalda','Piernas','Hombros'].map(value=><button className={muscle===value?'is-active':''} onClick={()=>setMuscle(value)} key={value}>{value}</button>)}</div><div className="m2-library-list">{filteredCatalog.slice(0,8).map(item=><Card as="button" type="button" onClick={()=>setDetail(item)} key={item.id}>{media(item)&&<img src={media(item)} alt="" loading="lazy"/>}<div><h2>{item.name}</h2><span><Target/>{item.category||item.body_part}</span><span><Dumbbell/>{item.equipment}</span><small>Ver detalle</small></div><ChevronRight/></Card>)}</div>{!filteredCatalog.length&&<Empty title="Sin resultados" text="Prueba otro término o filtro."/>}</>}
      {section==='progress'&&<><Card className="m2-period"><CalendarDays/>Esta semana<ChevronDown/></Card><div className="m2-workout-kpis"><Card><IconCircle><CalendarDays/></IconCircle><span>Sesiones completadas<strong>{workout.sessions?.length||0}/5</strong></span><i className="m2-progress"><b style={{width:`${Math.min(100,(workout.sessions?.length||0)*20)}%`}}/></i></Card><Card><IconCircle><Dumbbell/></IconCircle><span>Volumen total<strong>{Math.round((workout.sessions||[]).reduce((s,x)=>s+Number(x.totalVolume||0),0))} kg</strong></span><TrendingUp/></Card></div><div className="m2-progress-grid"><Card className="m2-chart"><h2>Volumen semanal</h2><div className="m2-line-chart">{[35,55,30,72,54,45,28].map((v,i)=><i key={i} style={{height:`${v}%`}}/>)}</div></Card><Card className="m2-compliance"><h2>Cumplimiento</h2><ProgressRing value={60} size={150}/><strong>3 de 5 sesiones</strong></Card></div><div className="m2-metrics-2"><Card><IconCircle><Flame/></IconCircle><span>Racha actual<strong>4 sesiones</strong></span></Card><Card><IconCircle><Activity/></IconCircle><span>Músculo más trabajado<strong>Pecho</strong></span></Card></div></>}
      {detail&&<FunctionalModal title={detail.name} onClose={()=>setDetail(null)}><div className="m2-exercise-detail">{media(detail)&&<img src={media(detail)} alt={detail.name} loading="lazy"/>}<p>{detail.category||detail.body_part} · {detail.equipment}</p><Button onClick={()=>{onUpdateWorkout(prev=>({...prev,favorites:Array.from(new Set([...(prev.favorites||[]),detail.id]))}));notify('Ejercicio guardado en favoritos');setDetail(null)}}><HeartPulse/>Guardar favorito</Button></div></FunctionalModal>}
    </div>;
  };

  const GoalsPage = ({ data, onUpdateDreamGoals, openAction }) => {
    const [section,setSection]=useQuerySection('goals','active',['active','completed','dreams']);const goals=data.dreamGoals||[];const visible=section==='completed'?goals.filter(g=>Number(g.current)>=Number(g.target)):section==='active'?goals.filter(g=>Number(g.current)<Number(g.target)):goals;
    return <div className="m2-page"><PageTitle title="Metas" subtitle="Ahorra hoy para construir el mañana que sueñas." action={<Button onClick={()=>openAction('goal')}><Plus/>Nueva meta</Button>}/><Tabs value={section} onChange={setSection} items={[{id:'active',label:'Activas'},{id:'completed',label:'Completadas'},{id:'dreams',label:'Sueños'}]}/>{section==='dreams'&&<Card className="m2-dream-intro"><IconCircle><Sparkles/></IconCircle><div><h2>Tus sueños, tu futuro.</h2><p>Convierte tus sueños en metas y hazlos realidad paso a paso.</p></div><span><small>Sueños guardados</small><strong>{goals.length}</strong><small>Valor total estimado</small><b>{money(goals.reduce((s,g)=>s+Number(g.target||0),0),'USD')}</b></span></Card>}<div className={`m2-goal-list ${section==='dreams'?'is-dreams':''}`}>{visible.length?visible.map((goal,index)=>{const pct=goal.target?Math.min(100,Math.round(Number(goal.current||0)/Number(goal.target)*100)):0;return <Card key={goal.id} className={index===0&&section==='active'?'is-featured':''}>{goal.image&&<img src={goal.image} alt=""/>}<div><h2>{goal.icon} {goal.title}</h2>{section==='completed'&&<em><CheckCircle2/>Completada</em>}<span>Meta<strong>{money(goal.target,'USD')}</strong></span>{section!=='dreams'&&<span>Ahorrado<strong className={section==='completed'?'is-green':''}>{money(goal.current,'USD')}</strong></span>}<i className="m2-progress"><b style={{width:`${pct}%`}}/></i><b className="m2-goal-pct">{pct}%</b>{section==='dreams'?<Button onClick={()=>setSection('active')}>Convertir en meta</Button>:section==='active'&&<Button onClick={()=>openAction('contribute',{goal})}>Aportar</Button>}</div></Card>}):<Empty title="No hay metas en esta sección" text="Tus metas aparecerán aquí cuando coincidan con este estado." action={()=>openAction('goal')} actionLabel="Nueva meta"/>}</div></div>;
  };

  const walletTabs=[{id:'summary',label:'Resumen',icon:BarChart3},{id:'accounts',label:'Cuentas',icon:CreditCard},{id:'movements',label:'Movimientos',icon:ArrowRightLeft},{id:'categories',label:'Categorías',icon:Target},{id:'export',label:'Exportar',icon:Download}];
  const WalletNav=({value,onChange})=><nav className="m2-wallet-nav" aria-label="Secciones de Wallet">{walletTabs.map(item=><button type="button" aria-current={value===item.id?'page':undefined} className={value===item.id?'is-active':''} key={item.id} onClick={()=>onChange(item.id)}><item.icon/><span>{item.label}</span></button>)}</nav>;
  const WalletPage = ({ data, onUpdateFinance, openAction, notify }) => {
    const [section,change]=useQuerySection('wallet','summary',['summary','add','accounts','movements','categories','export']); const [txType,setTxType]=useState('income'); const [search,setSearch]=useState(''); const [movementType,setMovementType]=useState('all'); const [categoryType,setCategoryType]=useState('expense'); const [currency,setCurrency]=useState('COP');
    const finance=data.financeData||{}; const rate=Number(finance.copRate||4000); const accounts=finance.accounts||[]; const tx=finance.transactions||[]; const categoryFilter=routeParam('category',''); const inCop=value=>Number(value||0)*rate; const total=accounts.reduce((s,a)=>s+inCop(a.balance),0); const currencyValue=value=>currency==='COP'?value:currency==='USD'?value/rate:value/(rate*1.08); const filteredTx=tx.filter(item=>(movementType==='all'||item.type===movementType)&&(!categoryFilter||item.category===categoryFilter)&&`${item.payee||''} ${item.note||''}`.toLowerCase().includes(search.toLowerCase()));
    const back=<button type="button" className="m2-back" aria-label="Volver al resumen de Wallet" onClick={()=>change('summary')}><ArrowLeft/></button>;
    const addTx=event=>{event.preventDefault();const fd=new FormData(event.currentTarget);const amountCop=Number(fd.get('amount')||0);const source=fd.get('account');const target=fd.get('target');if(!amountCop||!source)return;const amount=amountCop/rate;onUpdateFinance(prev=>({...prev,transactions:[{id:uid('fin'),type:txType,amount,category:fd.get('category')||'general',accountId:source,targetAccountId:target||null,payee:fd.get('note')||({income:'Ingreso',expense:'Gasto',transfer:'Transferencia'}[txType]),note:fd.get('note')||'',date:fd.get('date')||isoDate(),updatedAt:new Date().toISOString()},...(prev.transactions||[])],accounts:(prev.accounts||[]).map(account=>account.id===source?{...account,balance:Number(account.balance||0)+(txType==='income'?amount:-amount)}:txType==='transfer'&&account.id===target?{...account,balance:Number(account.balance||0)+amount}:account),updatedAt:new Date().toISOString()}));notify('Movimiento guardado y sincronizado');change('movements')};
    const exportData=()=>{const rows=[['tipo','fecha','descripción','monto_COP'],...tx.map(item=>[item.type,item.date,item.payee||item.note||'Movimiento',Math.round(inCop(item.amount))])];const csv=rows.map(row=>row.map(value=>`"${String(value??'').replaceAll('"','""')}"`).join(',')).join('\n');const blob=new Blob([`\uFEFF${csv}`],{type:'text/csv;charset=utf-8'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=`habitflow-wallet-${isoDate()}.csv`;a.click();URL.revokeObjectURL(url);notify('Archivo CSV generado')};
    const shell=content=><div className="m2-page">{content}<WalletNav value={section} onChange={change}/></div>;
    if(section==='add')return shell(<><PageTitle title="Agregar" subtitle="Registra un movimiento real." action={back}/><Card className="m2-impact"><span>Moneda<strong>COP</strong></span><hr/><span>Saldo actual<small>Entre todas tus cuentas</small><b>{money(total,'COP')}</b></span></Card><form className="m2-wallet-form" onSubmit={addTx}><Tabs value={txType} onChange={setTxType} items={[{id:'income',label:'Ingreso',icon:ArrowUp},{id:'expense',label:'Gasto',icon:ArrowDown},{id:'transfer',label:'Transferencia',icon:ArrowRightLeft}]}/><label>Monto<div><b>$</b><input name="amount" type="number" min="1" step="1" required placeholder="0"/><span>COP</span></div></label><label>Cuenta de origen<select name="account" required>{accounts.map(a=><option value={a.id} key={a.id}>{a.name}</option>)}</select></label>{txType==='transfer'&&<label>Cuenta de destino<select name="target" required defaultValue=""><option value="" disabled>Seleccionar cuenta</option>{accounts.map(a=><option value={a.id} key={a.id}>{a.name}</option>)}</select></label>}<label>Categoría<select name="category">{(finance.categories||[]).filter(c=>!c.type||c.type===txType).map(c=><option value={c.id} key={c.id}>{c.name}</option>)}</select></label><label>Fecha<input name="date" type="date" required defaultValue={isoDate()}/></label><label>Nota (opcional)<input name="note" placeholder="Escribe una nota..."/></label><Button type="submit">Guardar movimiento</Button></form></>);
    if(section==='accounts')return shell(<><PageTitle title="Cuentas" subtitle="Tus saldos sincronizados." action={<div className="m2-title-actions">{back}<Button onClick={()=>openAction('account')}><Plus/>Nueva cuenta</Button></div>}/><Card className="m2-account-summary"><span>Saldo total en cuentas<strong>{money(total,'COP')}</strong><small>≈ {money(total/rate,'USD')}</small></span><hr/><span>Cuentas activas<strong>{accounts.length}</strong><small>{accounts.length} registradas</small></span></Card><h2 className="m2-section-title">Mis cuentas</h2><div className="m2-account-list">{accounts.map((a,index)=><Card key={a.id}><IconCircle tone={agendaTone(index)}><CreditCard/></IconCircle><span><strong>{a.name}</strong><small>{a.type||'Cuenta'}</small></span><b className={Number(a.balance)<0?'is-red':''}>{money(inCop(a.balance),'COP')}</b><em>COP</em></Card>)}</div>{!accounts.length&&<Empty title="No hay cuentas" text="Crea una cuenta para comenzar." action={()=>openAction('account')} actionLabel="Nueva cuenta"/>}</>);
    if(section==='movements')return shell(<><PageTitle title="Movimientos" subtitle="Consulta y filtra tus registros." action={back}/><div className="m2-search"><Search/><input value={search} onChange={event=>setSearch(event.target.value)} placeholder="Buscar movimientos..."/></div><div className="m2-chip-row">{[['all','Todos'],['income','Ingresos'],['expense','Gastos'],['transfer','Transferencias']].map(([id,label])=><button key={id} className={movementType===id?'is-active':''} onClick={()=>setMovementType(id)}>{label}</button>)}</div><h2 className="m2-section-title">Recientes</h2><Card className="m2-movement-list">{filteredTx.map(item=><div key={item.id}><IconCircle tone={item.type==='income'?'green':item.type==='transfer'?'purple':'red'}>{item.type==='income'?<ArrowDown/>:item.type==='transfer'?<ArrowRightLeft/>:<CreditCard/>}</IconCircle><span><strong>{item.payee||item.note||'Movimiento'}</strong><small>{finance.categories?.find(c=>c.id===item.category)?.name||item.category}</small></span><time>{shortDate(item.date)}</time><b className={item.type==='income'?'is-green':item.type==='expense'?'is-red':''}>{item.type==='expense'?'-':'+'}{money(inCop(item.amount),'COP')}</b></div>)}</Card>{!filteredTx.length&&<Empty title="Sin movimientos" text="No hay resultados para este filtro."/>}</>);
    if(section==='categories')return shell(<><PageTitle title="Categorías" subtitle="Organiza ingresos y gastos." action={back}/><Tabs value={categoryType} onChange={setCategoryType} items={[{id:'expense',label:'Gastos'},{id:'income',label:'Ingresos'}]}/><h2 className="m2-section-title">Grupos de categorías</h2><div className="m2-category-list">{(finance.categories||[]).filter(cat=>!cat.type||cat.type===categoryType).map((cat,index)=><Card key={cat.id}><IconCircle tone={agendaTone(index)}><Target/></IconCircle><i style={{background:cat.color}}/><strong>{cat.name}</strong></Card>)}</div><Button onClick={()=>openAction('category')}><Plus/>Nueva categoría</Button></>);
    if(section==='export')return shell(<><PageTitle title="Exportar" subtitle="Descarga una copia legible de tus movimientos." action={back}/><Card className="m2-export-intro"><IconCircle><FileText/></IconCircle><span><h2>Archivo CSV</h2><p>Incluye tipo, fecha, descripción y monto de cada movimiento.</p></span></Card><Card className="m2-export-card"><h2>Contenido</h2>{['Movimientos','Fechas','Descripciones','Montos en COP'].map(item=><p key={item}><CheckCircle2/>{item}</p>)}<Button onClick={exportData}><Download/>Exportar ahora</Button><small>El archivo se genera únicamente en tu dispositivo.</small></Card></>);
    const income=tx.filter(i=>i.type==='income').reduce((s,i)=>s+inCop(i.amount),0);const expense=tx.filter(i=>i.type==='expense').reduce((s,i)=>s+inCop(i.amount),0);
    return shell(<><PageTitle title="Wallet" subtitle="Tus finanzas, siempre accesibles."/><div className="m2-currency">{['COP','USD','EUR'].map(value=><button key={value} className={currency===value?'is-active':''} onClick={()=>setCurrency(value)}>{value}</button>)}</div><div className="m2-wallet-total"><span>Saldo total</span><strong>{money(currencyValue(total),currency)}</strong><small>Base: {money(total,'COP')}</small></div><div className="m2-wallet-actions">{[['add','Agregar',Plus],['accounts','Cuentas',CreditCard],['movements','Movimientos',ArrowRightLeft],['categories','Categorías',Target],['export','Exportar',Download]].map(([id,label,Icon])=><button key={id} onClick={()=>change(id)}><Icon/><span>{label}</span></button>)}</div><Card className="m2-wallet-chart"><header><h2>Resumen del período</h2><span>Todos los registros</span></header><div className="m2-area-chart">{[15,22,19,31,38,43,40,55,61,70,68,88].map((v,i)=><i key={i} style={{height:`${v}%`}}/>)}</div><footer><span>Ingresos<strong className="is-green">{money(income,'COP')}</strong></span><span>Gastos<strong className="is-red">{money(expense,'COP')}</strong></span><span>Neto<strong>{money(income-expense,'COP')}</strong></span></footer></Card><h2 className="m2-section-title">Movimientos recientes</h2><Card className="m2-movement-list">{tx.slice(0,4).map(item=><div key={item.id}><IconCircle tone={item.type==='income'?'green':'red'}>{item.type==='income'?<ArrowDown/>:<CreditCard/>}</IconCircle><span><strong>{item.payee||item.note||'Movimiento'}</strong><small>{item.category}</small></span><time>{shortDate(item.date)}</time><b className={item.type==='income'?'is-green':'is-red'}>{item.type==='income'?'+':'-'}{money(inCop(item.amount),'COP')}</b></div>)}</Card></>);
  };

  const HealthPage = ({ data, hydration, brushing, addHydration, addBrushing, onUpdateHealth }) => {
    const health=data.healthData||{};const meds=(health.medications||[]).filter(m=>m.isActive!==false);const next=meds.flatMap(m=>(m.times||[]).map(time=>({med:m,time}))).sort((a,b)=>a.time.localeCompare(b.time))[0];const waterPct=hydration.goal?Math.round(hydration.amount/hydration.goal*100):0;const brushPct=brushing.goal?Math.round(brushing.count/brushing.goal*100):0;
    const take=()=>{if(!next)return;onUpdateHealth(prev=>({...prev,takenLogs:[...(prev.takenLogs||[]),{id:uid('dose'),medicationId:next.med.id,date:isoDate(),scheduledTime:next.time,status:'taken'}]}))};
    return <div className="m2-page"><PageTitle title="Salud" subtitle="Tu cuidado, a la vista"/><div className="m2-health-grid"><Card className="m2-health-water"><header><h2><Droplet/>Hidratación</h2><span><Flame/> {hydration.streak||0} días</span></header><div className="m2-bottles">{Array.from({length:5},(_,i)=><i className={i<Math.round(waterPct/20)?'is-filled':''} key={i}/>)}</div><div><strong>{(hydration.amount/1000).toFixed(2)} L</strong><span>de {(hydration.goal/1000).toFixed(2)} L</span><em>{waterPct}%</em></div><ProgressRing value={waterPct} size={106}/><footer><Button secondary onClick={()=>addHydration(250)}>+250 ml</Button><Button secondary onClick={()=>addHydration(500)}>+500 ml</Button></footer></Card><Card className="m2-health-brush"><header><h2><Tooth/>Cepillado dental</h2><span><Flame/>{brushing.streak||0} días</span></header><strong>{brushing.count} <small>/ {brushing.goal} cepillados hoy</small></strong><div className="m2-progress"><i style={{width:`${brushPct}%`}}/></div><Button secondary onClick={addBrushing}>Registrar</Button><footer>¡Sigue así! {brushing.streak||0} días consecutivos</footer></Card><Card className="m2-health-sleep"><header><h2><Moon/>Sueño</h2><span><Flame/>0 días</span></header><strong>{health.sleep?.lastHours||'--'} <small>Dormido anoche</small></strong><hr/><span>Hora de dormir<b>{health.sleep?.bedtime||'--:--'}</b><small>Meta: 7–9 h</small></span><ProgressRing value={health.sleep?.percentage||0} size={96}/></Card><Card className="m2-health-weight"><header><h2><Activity/>Peso</h2><span>Actualizado hoy</span></header><strong>{health.weight?.current||'--'} kg</strong><small>{health.weight?.change||0} kg vs. hace 7 días</small><div className="m2-weight-chart">{[55,58,62,57,49,50,45].map((v,i)=><i key={i} style={{bottom:`${v}%`}}/>)}</div></Card><Card className="m2-health-med"><header><h2><Pill/>Medicación</h2><span><Flame/>{meds.length} activas</span></header><span>Próxima dosis<strong>{next?`${next.med.name} ${next.med.dose}`:'Sin dosis pendientes'}</strong><em>{next?`Hoy, ${next.time}`:''}</em></span><Button secondary onClick={take} disabled={!next}>Marcar como tomada</Button><footer><Bell/>Recordatorio activo · {next?.time||'--:--'}</footer></Card></div></div>;
  };

  const SettingsPage = ({ data, onUpdateUser, onNotifications, notify }) => {
    const [name,setName]=useState(data.user?.name||'');
    const saveProfile=event=>{event.preventDefault();onUpdateUser({name:name.trim()||'Usuario',updatedAt:new Date().toISOString()});notify('Perfil actualizado')};
    return <div className="m2-page"><PageTitle title="Configuración" subtitle="Personaliza HabitFlow."/><Card className="m2-settings"><form onSubmit={saveProfile}><h2>Perfil</h2><label>Nombre<input value={name} onChange={event=>setName(event.target.value)} required/></label><Button type="submit">Guardar nombre</Button></form><hr/><h2>Tema</h2><div className="m2-two-actions"><Button secondary={data.user?.themeMode!=='pureDark'} onClick={()=>onUpdateUser({themeMode:'pureDark'})}>Dark Puro</Button><Button secondary={data.user?.themeMode!=='pinkLight'} onClick={()=>onUpdateUser({themeMode:'pinkLight'})}>Claro Rosa</Button></div><hr/><h2>Notificaciones</h2><p>Autoriza este dispositivo para recibir recordatorios.</p><Button secondary onClick={onNotifications}><Bell/>Configurar notificaciones</Button><hr/><h2>Sincronización</h2><p>Tus cambios se guardan automáticamente en la nube.</p><Button secondary onClick={()=>global.Clerk?.signOut?.()}><ArrowLeft/>Cerrar sesión</Button></Card></div>;
  };

  const MobileTabletV2App = (props) => {
    const { data, view, navigate, moreOpen, setMoreOpen, creatorAccess, streak, dateLabel, onNotifications } = props;
    const [action,setAction]=useState(null); const [feedback,setFeedback]=useState('');
    const notify=useCallback(message=>{setFeedback(message);global.clearTimeout(MobileTabletV2App.feedbackTimer);MobileTabletV2App.feedbackTimer=global.setTimeout(()=>setFeedback(''),3200)},[]);
    const openAction=useCallback((type,extra={})=>setAction({type,...extra}),[]);
    const navigateSafely=useCallback((next,options)=>{setMoreOpen(false);navigate(next,options)},[navigate,setMoreOpen]);
    useEffect(()=>{if(!props.pendingQuickAction)return;const map={task:'task',habit:'habit',expense:'expense',goal:'goal',routine:'routine'};const type=map[props.pendingQuickAction.action||props.pendingQuickAction.type];if(type)openAction(type);props.onQuickActionHandled?.(props.pendingQuickAction.id)},[props.pendingQuickAction,props.onQuickActionHandled,openAction]);
    const handlers={onUpdateAgenda:props.onUpdateAgenda,onAddHabit:props.onAddHabit,onUpdateFinance:props.onUpdateFinance,onUpdateDreamGoals:props.onUpdateDreamGoals,onUpdateWorkout:props.onUpdateWorkout,onCreateHabitCategory:props.onCreateHabitCategory,HabitForm:props.HabitForm,habitCategories:props.habitCategories};
    let page;
    if(view==='dashboard')page=<HomePage data={data} navigate={navigateSafely} openAction={openAction} streak={streak} onCompleteHabit={props.onCompleteHabit} onUpdateAgenda={props.onUpdateAgenda} onUpdateUser={props.onUpdateUser} onUpdatePomodoro={props.onUpdatePomodoro} onQuickPomodoroComplete={props.onQuickPomodoroComplete}/>;
    else if(view==='habits')page=<HabitsPage data={data} onCompleteHabit={props.onCompleteHabit} hydration={props.hydration} onToggleHydrationWidget={props.onToggleHydrationWidget} openAction={openAction}/>;
    else if(view==='pomodoro')page=<PomodoroPage data={data} onUpdatePomodoro={props.onUpdatePomodoro} onUpdateUser={props.onUpdateUser} onUpdateAgenda={props.onUpdateAgenda} openAction={openAction}/>;
    else if(view==='agenda')page=<AgendaPage data={data} onUpdateAgenda={props.onUpdateAgenda} openAction={openAction}/>;
    else if(view==='workout')page=<WorkoutPage data={data} onUpdateWorkout={props.onUpdateWorkout} openAction={openAction} notify={notify}/>;
    else if(view==='dreams')page=<GoalsPage data={data} onUpdateDreamGoals={props.onUpdateDreamGoals} openAction={openAction}/>;
    else if(view==='finance')page=<WalletPage data={data} onUpdateFinance={props.onUpdateFinance} openAction={openAction} notify={notify}/>;
    else if(view==='health')page=<HealthPage data={data} hydration={props.hydration} brushing={props.brushing} addHydration={props.addHydration} addBrushing={props.addBrushing} onUpdateHealth={props.onUpdateHealth}/>;
    else page=<SettingsPage data={data} onUpdateUser={props.onUpdateUser} onNotifications={onNotifications} notify={notify}/>;
    return <div className={`mobile-v2 mobile-v2-${view}`} data-testid="mobile-tablet-v2-shell"><MobileV2Header userName={data.user?.name} streak={streak} avatarUrl={props.avatarUrl} onProfile={props.onProfile}/><main id="habitflow-main" tabIndex="-1">{page}</main><MobileV2BottomNav view={view} onNavigate={navigateSafely} moreOpen={moreOpen} onToggleMore={()=>setMoreOpen(!moreOpen)} workoutActive={view==='workout'}/><MobileV2MoreSheet open={moreOpen} view={view} onClose={()=>setMoreOpen(false)} onNavigate={navigateSafely} creatorAccess={creatorAccess}/>{action&&<ActionCenter action={action} onClose={()=>setAction(null)} data={data} handlers={handlers} notify={notify}/>} {feedback&&<div className="m2-feedback" role="status">{feedback}</div>}</div>;
  };

  global.HabitFlowMobileV2 = Object.freeze({ MobileTabletV2App, useMobileV2Viewport });
})(window);
